import{_ as a,o,c as d,ag as l}from"./chunks/framework.eQLvDOR_.js";const p=JSON.parse('{"title":"Claude Code 上下文开销 (Claude Code Overhead)","description":"","frontmatter":{},"headers":[],"relativePath":"wiki/concepts/claude-code-overhead.md","filePath":"wiki/concepts/claude-code-overhead.md","lastUpdated":null}'),t={name:"wiki/concepts/claude-code-overhead.md"};function r(i,e,c,n,s,u){return o(),d("div",null,[...e[0]||(e[0]=[l('<h1 id="claude-code-上下文开销-claude-code-overhead" tabindex="-1">Claude Code 上下文开销 (Claude Code Overhead) <a class="header-anchor" href="#claude-code-上下文开销-claude-code-overhead" aria-label="Permalink to &quot;Claude Code 上下文开销 (Claude Code Overhead)&quot;">​</a></h1><h2 id="核心定义" tabindex="-1">核心定义 <a class="header-anchor" href="#核心定义" aria-label="Permalink to &quot;核心定义&quot;">​</a></h2><p>在使用 Claude Code 等 CLI AI 助手时，由于配置不当或隐藏机制导致的不必要的 Token 消耗。</p><h2 id="消耗陷阱" tabindex="-1">消耗陷阱 <a class="header-anchor" href="#消耗陷阱" aria-label="Permalink to &quot;消耗陷阱&quot;">​</a></h2><ul><li><strong>冗余的 Plugin Hooks</strong>: 每次提问或会话启动时自动注入的环境信息（如 <code>UserPromptSubmit</code>, <code>SessionStart</code>）。未清理的 Hooks 会在每次对话中成倍消耗 Input Token。</li><li><strong>庞大的 CLAUDE.md</strong>: 过长或包含大量无关上下文的系统指令，会占用每轮对话的基础窗口。</li><li><strong>MCP 连接过多</strong>: 连接的 MCP Server 如果在当前任务中不需要，其暴露的 Tool Schema 依然会占用大量 Token。</li></ul><h2 id="优化策略" tabindex="-1">优化策略 <a class="header-anchor" href="#优化策略" aria-label="Permalink to &quot;优化策略&quot;">​</a></h2><ul><li>定期审计并禁用不必要的 Plugin Hooks (<code>/plugin disable &lt;plugin-name&gt;</code>)。</li><li>动态管理 MCP Servers (<code>/mcp disable &lt;server&gt;</code>)。</li><li>保持 <code>CLAUDE.md</code> 精简，使用指令链或 Skill 动态加载需要的上下文。</li></ul><h2 id="关联概念" tabindex="-1">关联概念 <a class="header-anchor" href="#关联概念" aria-label="Permalink to &quot;关联概念&quot;">​</a></h2><ul><li>[[context-optimization]]</li><li>[[token-consumption-traps]]</li></ul>',9)])])}const m=a(t,[["render",r]]);export{p as __pageData,m as default};
